from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

conn = psycopg2.connect("dbname=your_db user=your_user")
cur = conn.cursor()

@app.route('/query', methods=['GET'])
def query_data():
    table_name = request.args.get('table_name')
    column_names = request.args.get('column_names')
    filter_condition = request.args.get('filter_condition')

    query = f"SELECT {column_names} FROM {table_name} WHERE {filter_condition};"
    cur.execute(query)
    data = cur.fetchall()

    return jsonify(data)

